// Runs the REAL TS reference port (apps/monster-studio/src/lib/lattice-quantizer.ts)
// over the golden E8 inputs and emits expected outputs for parity comparison.
// Node 23+ strips TS types from the dynamic import automatically.
import { readFileSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const __dirname = dirname(fileURLToPath(import.meta.url));
const TS = join(
  __dirname,
  "../../../../../apps/monster-studio/src/lib/lattice-quantizer.ts",
);

const { nearestE8 } = await import(TS);

const golden = JSON.parse(readFileSync(join(__dirname, "golden_e8.json"), "utf8"));
const out = golden.map((v) => {
  const q = nearestE8(v);
  let err = 0;
  for (let i = 0; i < 8; i++) {
    const e = v[i] - q[i];
    err += e * e;
  }
  return { q, err };
});
writeFileSync(join(__dirname, "ts_e8_expected.json"), JSON.stringify(out));
console.log(`TS port: wrote ${out.length} E8 expected outputs`);
